import{_ as o,o as t,c as n,ag as a}from"./chunks/framework.1N8rnUr9.js";const g=JSON.parse('{"title":"Connection Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/connection.md","filePath":"guide/connection.md","lastUpdated":null}'),r={name:"guide/connection.md"};function i(s,e,c,l,u,d){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="connection-guide" tabindex="-1">Connection Guide <a class="header-anchor" href="#connection-guide" aria-label="Permalink to &quot;Connection Guide&quot;">​</a></h1><p>To start using TubeBay, you need to connect your YouTube account. This allows the plugin to read your video library and synchronize content to your WooCommerce store.</p><p>TubeBay offers two connection methods: <strong>Google OAuth (Recommended)</strong> and <strong>Manual API Key</strong>.</p><h2 id="google-oauth-2-0-recommended" tabindex="-1">Google OAuth 2.0 (Recommended) <a class="header-anchor" href="#google-oauth-2-0-recommended" aria-label="Permalink to &quot;Google OAuth 2.0 (Recommended)&quot;">​</a></h2><p>This is the easiest and most secure way to connect. It uses our secure authentication proxy to link your account without requiring you to create a Google Cloud project.</p><h3 id="steps-to-connect" tabindex="-1">Steps to Connect: <a class="header-anchor" href="#steps-to-connect" aria-label="Permalink to &quot;Steps to Connect:&quot;">​</a></h3><ol><li>Navigate to <strong>TubeBay &gt; Settings</strong> in your WordPress dashboard.</li><li>Select the <strong>Google OAuth</strong> tab.</li><li>Click the <strong>Connect with Google</strong> button.</li><li>You will be redirected to Google to authorize TubeBay.</li><li>Once authorized, you will receive a <strong>Refresh Token</strong>. Copy this token.</li><li>Paste the token into the <strong>Refresh Token</strong> field in your WordPress dashboard and click <strong>Connect</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Security</p><p>OAuth is safer because it doesn&#39;t give TubeBay your password and allows you to revoke access at any time from your Google Account settings.</p></div><h2 id="manual-api-key-advanced" tabindex="-1">Manual API Key (Advanced) <a class="header-anchor" href="#manual-api-key-advanced" aria-label="Permalink to &quot;Manual API Key (Advanced)&quot;">​</a></h2><p>If you prefer to use your own Google Cloud project and API credentials, you can use the Manual method.</p><h3 id="steps-to-connect-1" tabindex="-1">Steps to Connect: <a class="header-anchor" href="#steps-to-connect-1" aria-label="Permalink to &quot;Steps to Connect:&quot;">​</a></h3><ol><li>Navigate to the <a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">Google Cloud Console</a>.</li><li>Create a new project and enable the <strong>YouTube Data API v3</strong>.</li><li>Create an <strong>API Key</strong> credentials.</li><li>Go to <strong>TubeBay &gt; Settings</strong> and select the <strong>Manual API</strong> tab.</li><li>Enter your <strong>API Key</strong> and your <strong>YouTube Channel ID</strong>.</li><li>Click <strong>Connect</strong>.</li></ol><h3 id="how-to-find-your-channel-id" tabindex="-1">How to find your Channel ID? <a class="header-anchor" href="#how-to-find-your-channel-id" aria-label="Permalink to &quot;How to find your Channel ID?&quot;">​</a></h3><p>You can find your YouTube Channel ID by visiting your <a href="https://www.youtube.com/account_advanced" target="_blank" rel="noreferrer">YouTube Account Advanced Settings</a>. It usually starts with <code>UC...</code>.</p><h2 id="verifying-the-connection" tabindex="-1">Verifying the Connection <a class="header-anchor" href="#verifying-the-connection" aria-label="Permalink to &quot;Verifying the Connection&quot;">​</a></h2><p>Once connected, TubeBay will attempt to fetch your channel details (Name and Thumbnail). If successful, your connection status will change to <strong>Connected</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Connection Errors</p><p>If you see an error message, double-check your API key or ensure your Google project has the YouTube Data API enabled.</p></div>',17)])])}const y=o(r,[["render",i]]);export{g as __pageData,y as default};
